# --- spec / context types -----------------------------------------------------


class ScoreFn(Protocol):
    """Stateful score callable handed to train_fn.

    Calling `score(kind, model)` runs `spec.eval_forward(model, batch)` over
    `val_loaders[kind]`, computes the metric, returns it, and updates the
    harness-owned running best for `kind`.
    """

    def __call__(self, kind: str, model: nn.Module) -> float: ...
    def best(self, kind: str) -> float: ...


@dataclass
class TrainContext:
    fabric: L.Fabric
    model: nn.Module  # fabric.setup'd
    # The project config from build_spec()'s ExperimentSpec. This is where
    # train_fn reads its hyperparameters (lr, weight decay, etc.).
    cfg: dict[str, Any]
    train_loader: DataLoader[Any]
    val_loaders: dict[str, DataLoader[Any]]
    budget_sec: float
    score: ScoreFn
    recorder: Recorder


@dataclass
class TrainResult:
    num_steps: int
    training_seconds: float


EvalForward = Callable[["nn.Module", dict[str, Any]], "torch.Tensor"]
TrainFn = Callable[[TrainContext], TrainResult]


@dataclass(frozen=True)
class ExperimentSpec:
    """The contract returned by `train.build_spec()`.

    The harness builds dataloaders from `cfg` + `max_items`, computes
    `num_params_M` + `depth` by introspecting `model`, runs `train_fn` with a
    `TrainContext`, and reads `score.best(kind)` after.

    `cfg` is a free-form project config dict (feature flags, architecture
    knobs, anything train.py wants to thread through to the data builders).
    """

    cfg: dict[str, Any]
    max_items: int
    model: nn.Module
    train_fn: TrainFn
    eval_forward: EvalForward


