def emit_summary(metrics: dict[str, Any]) -> None:
    """Print the summary block to stdout.

    Format is load-bearing: the launcher greps ``^<primary_metric>:`` and reads
    field 2. The primary metric MUST be the FIRST printed line so the grep
    contract picks the right value.
    """
    print("---")
    # TODO(autoresearch): rename val_metric to your primary metric. Apply the
    # SAME rename in all coupled spots or you'll KeyError on first run:
    # (1) this key, (2) the "val_metric" key in run_experiment's return dict,
    # (3) the `val_metric = ...` local in run_experiment that feeds that key.
    print(f"val_metric:       {metrics['val_metric']:.6f}")
    print(f"training_seconds: {metrics['training_seconds']:.1f}")
    print(f"total_seconds:    {metrics['total_seconds']:.1f}")
    print(f"peak_vram_mb:     {metrics['peak_vram_mb']:.1f}")
    print(f"num_steps:        {metrics['num_steps']}")
    print(f"num_params_M:     {metrics['num_params_M']:.1f}")
    print(f"depth:            {metrics['depth']}")


def update_best(current_best: float, candidate: float) -> float:
    """Take max(current_best, candidate) with NaN safety."""
    cb_nan = math.isnan(current_best)
    cand_nan = math.isnan(candidate)
    if cb_nan and cand_nan:
        return math.nan
    if cb_nan:
        return candidate
    if cand_nan:
        return current_best
    return max(current_best, candidate)


def _introspect_depth(model: nn.Module) -> int:
    """Best-effort depth introspection. train.py can override by setting
    `model.n_layers = N` for a clean self-report."""
    n = getattr(model, "n_layers", None)
    if isinstance(n, int):
        return n
    try:
        from torch import nn

        return sum(
            1 for m in model.modules() if isinstance(m, nn.TransformerEncoderLayer)
        )
    except Exception:  # noqa: BLE001
        return 0


