def _make_score_fn(
    fabric: L.Fabric,
    val_loaders: dict[str, DataLoader[Any]],
    eval_forward: EvalForward,
    recorder: Recorder,
) -> ScoreFn:
    import torch

    # `fabric` is threaded through for the copier's real metric impl (e.g.
    # `fabric.device` when moving targets onto the accelerator); not dead.
    best: dict[str, float] = {kind: math.nan for kind in val_loaders}

    class _Score:
        def __call__(self, kind: str, model: nn.Module) -> float:
            loader = val_loaders[kind]
            was_training = model.training
            model.eval()
            # TODO(autoresearch): plug your metric here (the ONE place the
            # metric lives). Iterate `loader`, run `eval_forward(model, batch)`,
            # read the target from `batch`, and reduce to the scalar `val`.
            with torch.no_grad():
                for batch in loader:
                    preds = eval_forward(model, batch)
                    del preds  # replace with metric accumulation
            val = _compute_metric_stub()
            best[kind] = update_best(best[kind], val)
            recorder.log(f"val_metric/{kind}", val, step=recorder.last_step())
            if was_training:
                model.train()
            return val

        def best(self, kind: str) -> float:
            return best[kind]

    return _Score()


def run_experiment(
    spec: ExperimentSpec, *, budget_min: float = DEFAULT_BUDGET_MIN
) -> dict[str, Any]:
    """Run one experiment within `budget_min` wall-clock minutes."""
    import os
    import time

    import lightning as L
    import torch

    t_total_start = time.monotonic()
    crashed = False
    crash_reason = ""
    result = TrainResult(num_steps=0, training_seconds=0.0)

    try:
        num_params_m = sum(p.numel() for p in spec.model.parameters()) / 1e6
    except Exception:  # noqa: BLE001
        num_params_m = 0.0
    depth = _introspect_depth(spec.model)

    recorder = Recorder()
    score_fn: ScoreFn | None = None
    try:
        torch.set_float32_matmul_precision("medium")
        fabric = L.Fabric(accelerator="gpu", devices=1, precision="bf16-mixed")
        fabric.launch()

        seed = int(os.environ.get("AUTORES_SEED", SEED))
        fabric.seed_everything(seed)

        train_loader = build_train_dataloader(spec.cfg)
        val_loaders = build_val_dataloaders(spec.cfg)

        model = fabric.setup(spec.model)
        train_loader = fabric.setup_dataloaders(train_loader)
        val_loaders = {
            kind: fabric.setup_dataloaders(loader)
            for kind, loader in val_loaders.items()
        }

        score_fn = _make_score_fn(
            fabric, val_loaders, spec.eval_forward, recorder
        )

        ctx = TrainContext(
            fabric=fabric,
            model=model,
            cfg=spec.cfg,
            train_loader=train_loader,
            val_loaders=val_loaders,
            budget_sec=budget_min * 60.0,
            score=score_fn,
            recorder=recorder,
        )
        result = spec.train_fn(ctx)

    except torch.cuda.OutOfMemoryError as exc:  # type: ignore[attr-defined]
        crashed, crash_reason = True, f"OOM: {exc}"
    except Exception as exc:  # noqa: BLE001
        crashed, crash_reason = True, f"{type(exc).__name__}: {exc}"
    finally:
        write_dynamics_csv(
            "run_dynamics.csv",
            series=recorder.snapshot(),
            meta={
                "num_steps": str(result.num_steps),
                "crashed": str(crashed).lower(),
                "budget_sec": f"{budget_min * 60.0:.0f}",
            },
        )

    t_total_elapsed = time.monotonic() - t_total_start
    peak_vram_mb = (
        torch.cuda.max_memory_allocated() / 1024**2
        if torch.cuda.is_available()
        else 0.0
    )

    best_primary = (
        score_fn.best(PRIMARY_VAL_KIND) if score_fn is not None else math.nan
    )
    val_metric = (
        best_primary if not crashed and not math.isnan(best_primary) else 0.0
    )

    if crashed:
        import sys

        print(f"[autores] crashed: {crash_reason}", file=sys.stderr)

    return {
        "val_metric": val_metric,
        "training_seconds": result.training_seconds,
        "total_seconds": t_total_elapsed,
        "peak_vram_mb": peak_vram_mb,
        "num_steps": result.num_steps,
        "num_params_M": num_params_m,
        "depth": depth,
        "crashed": crashed,
    }
